var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 기록보존실     \\n<color=#ffd34c>제 64 재난지구</color>     \\nCCTV 관련기록 편집 영상 #2","JPN":"管理局の記録保管室     \\n<color=#ffd34c>第64災害地区</color>     \\n監視カメラの関連記録編集映像#2","ENG":"[[","TWN":"管理局 檔案室     \\n<color=#ffd34c>第 64 災難地球</color>     \\nCCTV 相關記錄 編輯影像 #2","THA":"ห้องเก็บบันทึกขององค์การบริหารโลก     \\n<color=#ffd34c>เขตภัยพิบัติที่ 64</color>     \\nวิดีโอจากกล้องวงจรปิดที่ถูกตัดต่อ #2","VTN":"Phòng Lưu Trữ Hồ Sơ Hành Chính     \\n<color=#ffd34c>Địa Hạt Tai Họa Thứ 64</color>     \\nHồ Sơ Video CCTV Đã Chỉnh Sửa #2","SCN":"管理局 档案室     \\n<color=#ffd34c>第 64 灾难地球</color>     \\n摄像 相关记录 编辑影像 #2","DEU":"[[","FRA":"Salle des archives de l'Administration     \\n<color=#ffd34c>64e zone sinistrée</color>     \\nMontage de vidéosurveillance #2"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"......그래서 꼬마 아가씨가 카운터 능력자라고?","JPN":"……それで、お嬢ちゃんがカウンターなのかい？","ENG":"So, our little lady here is a Counter?","TWN":"……所以妳這小女孩是制裁者？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"그, 그래!","JPN":"そ、そうだよ！","ENG":"Y-yeah!","TWN":"沒、沒錯！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"카운터가 일을 도와준다면 특식 배급표 스무 장을 준다고 한 건 사실이겠지?","JPN":"カウンターが仕事を手伝えば、特別食の配給票を20枚くれるんだよね？","ENG":"Are you really going to give 20 special food stamps if a Counter helps you out?","TWN":"如果制裁者來幫忙，會特別給20張糧票是真的嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 물론이지. 등급에 따라서는 더 많이 줄 수도 있어.","JPN":"ああ、もちろんだ。ランクによっては、もっとたくさんやってもいい。","ENG":"Oh, of course. I can give more based on your grade.","TWN":"啊，當然。根據制裁者等級，甚至會給更多。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"제대로 된 카운터가 맞기만 하다면 말이야.","JPN":"もちろん、ちゃんとしたカウンターだったらの話だが。","ENG":"But only if you're a real Counter.","TWN":"只要是個像樣的制裁者就行了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"무슨 뜻이야? 내, 내가 지금 거짓말이라도 하고 있다는 거야?","JPN":"どういう意味？わ、私が嘘をついてるって言うの？","ENG":"What do you mean by that? Y-you think I'm lying about this?","TWN":"你是什麼意思？你是說我在說謊嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 말은 하지 않았어. 꼬마 아가씨.","JPN":"いや、そういうわけじゃない。","ENG":"I didn't say that, little lady.","TWN":"我可沒說那種話。小妞。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 일은 확실할수록 좋은 거지. 내 입장에서 생각해 보라고.","JPN":"だが、確認するのは大事だからな。俺の立場になってみろ。","ENG":"But I just want confirmation. Try looking at this from my side.","TWN":"但是事情越確定越好，站在我的立場想想看。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"아무 시계나 차고 온 사기꾼들이 자기가 카운터 능력자라고 하는 걸 전부 곧이곧대로 믿어 주다간, ","JPN":"適当な時計を持った嘘つきの言葉まで、いちいち鵜呑みにしてたら、","ENG":"If I just believe anyone who's wearing a watch, claiming to be a Counter, ","TWN":"如果那些騙子戴個手錶就說自己制裁者，而我們就這相信他們的話……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"난 금방 파산해서 거지가 될 거 아니겠어?","JPN":"俺だって破産しちまう。","ENG":"I'll end up broke and out of business.","TWN":"那我不是一下就破產，要去當乞丐了嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"그, 그럼 어떻게 해야......","JPN":"じゃ、じゃあ、どうすれば……","ENG":"Th-then what can I do?","TWN":"那、那我該怎麼做……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"......일단은 간단한 문답부터 시작해 볼까.","JPN":"……とりあえず、簡単な質問から答えてもらおうか。","ENG":"Let's start with some simple questions.","TWN":"……我們姑且從簡單的問答開始吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"그 워치는 어디서 얻은 거지?","JPN":"そのウォッチは、誰からもらったんだ？","ENG":"Where did you get that Watch?","TWN":"妳是從哪裡得到那個能量環的？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"이건...... 난민 구호소에서 만난 어떤 아저씨에게 받은 거야.","JPN":"これは……、難民救護所で会ったおじさんからもらったの。","ENG":"This was... given to me by some man I met at the refugee shelter.","TWN":"這是……在難民救護所遇到的某個叔叔給我的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOONSEO_KID_NULL_NULL","text":{"KOREA":"누군지는 나도 몰라.","JPN":"知らないおじさんだった。","ENG":"I have no idea who he was.","TWN":"我不知道他是誰。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"카운터 워치를 그냥 줬다고? 그것도 생판 모르는 남에게?","JPN":"カウンターウォッチをタダでもらったのか？しかも、見ず知らずのやつから？","ENG":"He just gave you a Counter Watch? A complete stranger?","TWN":"把制裁者的能量環直接給妳了？而且還是給陌生人？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};